package com.example.dacs3_ticket_booking_app.ui.view.admin

import android.content.Intent
import android.os.Bundle
import android.text.Editable
import android.text.TextWatcher
import android.view.View
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.ViewModelProvider
import androidx.recyclerview.widget.LinearLayoutManager
import com.example.dacs3_ticket_booking_app.databinding.ActivityAdminUserListBinding
import com.example.dacs3_ticket_booking_app.ui.view.adapter.AdminUserAdapter
import com.example.dacs3_ticket_booking_app.ui.viewmodel.UserViewModel

class AdminUserListActivity : AppCompatActivity() {
    private lateinit var binding: ActivityAdminUserListBinding
    private lateinit var userViewModel: UserViewModel
    private var allUsers = listOf<com.example.dacs3_ticket_booking_app.data.model.User>()
    private lateinit var sharedPreferences: android.content.SharedPreferences

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        binding = ActivityAdminUserListBinding.inflate(layoutInflater)
        setContentView(binding.root)

        userViewModel = ViewModelProvider(this).get(UserViewModel::class.java)
        sharedPreferences = getSharedPreferences("app_prefs", MODE_PRIVATE)

        setupRecyclerView()
        setupSearchListener()
        observeViewModel()

        binding.backBtn.setOnClickListener { finish() }
        binding.fabAddUser.setOnClickListener {
            startActivity(Intent(this, AdminUserFormActivity::class.java))
        }

        userViewModel.getAllUsers()
    }

    override fun onResume() {
        super.onResume()
        userViewModel.getAllUsers()
    }

    private fun setupRecyclerView() {
        binding.recyclerViewUsers.layoutManager = LinearLayoutManager(this)
    }

    private fun setupSearchListener() {
        binding.etSearchUser.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) {}

            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                val query = s.toString().trim().lowercase()

                // Filter users real-time
                val filtered = if (query.isEmpty()) {
                    allUsers
                } else {
                    allUsers.filter { user ->
                        user.fullName.lowercase().contains(query) ||
                        user.email.lowercase().contains(query)
                    }
                }

                updateAdapter(filtered)
            }

            override fun afterTextChanged(s: Editable?) {}
        })
    }

    private fun observeViewModel() {
        userViewModel.users.observe(this) { users ->
            // ✅ Lấy userId từ SharedPreferences (stable, không thay đổi)
            val currentUserId = sharedPreferences.getString("userId", "")

            allUsers = if (!currentUserId.isNullOrEmpty()) {
                users.filter { it.id != currentUserId }
            } else {
                users
            }

            // Cập nhật adapter với dữ liệu hiện tại (hoặc kết quả tìm kiếm)
            val query = binding.etSearchUser.text.toString().trim().lowercase()
            val filtered = if (query.isEmpty()) {
                allUsers
            } else {
                allUsers.filter { user ->
                    user.fullName.lowercase().contains(query) ||
                    user.email.lowercase().contains(query)
                }
            }

            updateAdapter(filtered)
        }

        userViewModel.isLoading.observe(this) { isLoading ->
            binding.progressBar.visibility = if (isLoading) View.VISIBLE else View.GONE
        }

        userViewModel.errorMessage.observe(this) { msg ->
            Toast.makeText(this, msg, Toast.LENGTH_SHORT).show()
        }

        userViewModel.successMessage.observe(this) { msg ->
            Toast.makeText(this, msg, Toast.LENGTH_SHORT).show()
        }
    }

    private fun updateAdapter(users: List<com.example.dacs3_ticket_booking_app.data.model.User>) {
        binding.recyclerViewUsers.adapter = AdminUserAdapter(
            users.toMutableList(),
            onEdit = { user ->
                val intent = Intent(this, AdminUserFormActivity::class.java)
                intent.putExtra("user", user)
                startActivity(intent)
            },
            onDelete = { user ->
                userViewModel.deleteUser(user.id)
            }
        )
    }
}

package com.example.dacs3_ticket_booking_app.ui.view.admin

import android.content.Intent
import android.os.Bundle
import android.text.Editable
import android.text.TextWatcher
import android.view.View
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.ViewModelProvider
import androidx.recyclerview.widget.LinearLayoutManager
import com.example.dacs3_ticket_booking_app.databinding.ActivityAdminUserListBinding
import com.example.dacs3_ticket_booking_app.ui.view.adapter.AdminUserAdapter
import com.example.dacs3_ticket_booking_app.ui.viewmodel.UserViewModel

class AdminUserListActivity : AppCompatActivity() {
    private lateinit var binding: ActivityAdminUserListBinding
    private lateinit var userViewModel: UserViewModel
    private var allUsers = listOf<com.example.dacs3_ticket_booking_app.data.model.User>()
    private lateinit var sharedPreferences: android.content.SharedPreferences

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        binding = ActivityAdminUserListBinding.inflate(layoutInflater)
        setContentView(binding.root)

        userViewModel = ViewModelProvider(this).get(UserViewModel::class.java)
        sharedPreferences = getSharedPreferences("app_prefs", MODE_PRIVATE)

        setupRecyclerView()
        setupSearchListener()
        observeViewModel()

        binding.backBtn.setOnClickListener { finish() }
        binding.fabAddUser.setOnClickListener {
            startActivity(Intent(this, AdminUserFormActivity::class.java))
        }

        userViewModel.getAllUsers()
    }

    override fun onResume() {
        super.onResume()
        userViewModel.getAllUsers()
    }

    private fun setupRecyclerView() {
        binding.recyclerViewUsers.layoutManager = LinearLayoutManager(this)
    }

    private fun setupSearchListener() {
        binding.etSearchUser.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) {}

            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                val query = s.toString().trim().lowercase()

                // Filter users real-time
                val filtered = if (query.isEmpty()) {
                    allUsers
                } else {
                    allUsers.filter { user ->
                        user.fullName.lowercase().contains(query) ||
                        user.email.lowercase().contains(query)
                    }
                }

                updateAdapter(filtered)
            }

            override fun afterTextChanged(s: Editable?) {}
        })
    }

    private fun observeViewModel() {
        userViewModel.users.observe(this) { users ->
            // ✅ Lấy userId từ SharedPreferences (stable, không thay đổi)
            val currentUserId = sharedPreferences.getString("userId", "")

            // Debug log
            android.util.Log.d("AdminUserList", "currentUserId from SharedPreferences: '$currentUserId'")
            android.util.Log.d("AdminUserList", "Total users: ${users.size}")

            allUsers = if (!currentUserId.isNullOrEmpty()) {
                val filtered = users.filter { it.id != currentUserId }
                android.util.Log.d("AdminUserList", "After filter: ${filtered.size}")
                filtered
            } else {
                android.util.Log.d("AdminUserList", "currentUserId is empty, showing all users")
                users
            }

            // Cập nhật adapter với dữ liệu hiện tại (hoặc kết quả tìm kiếm)
            val query = binding.etSearchUser.text.toString().trim().lowercase()
            val filtered = if (query.isEmpty()) {
                allUsers
            } else {
                allUsers.filter { user ->
                    user.fullName.lowercase().contains(query) ||
                    user.email.lowercase().contains(query)
                }
            }

            updateAdapter(filtered)
        }

        userViewModel.isLoading.observe(this) { isLoading ->
            binding.progressBar.visibility = if (isLoading) View.VISIBLE else View.GONE
        }

        userViewModel.errorMessage.observe(this) { msg ->
            Toast.makeText(this, msg, Toast.LENGTH_SHORT).show()
        }

        userViewModel.successMessage.observe(this) { msg ->
            Toast.makeText(this, msg, Toast.LENGTH_SHORT).show()
        }
    }

    private fun updateAdapter(users: List<com.example.dacs3_ticket_booking_app.data.model.User>) {
        binding.recyclerViewUsers.adapter = AdminUserAdapter(
            users.toMutableList(),
            onEdit = { user ->
                val intent = Intent(this, AdminUserFormActivity::class.java)
                intent.putExtra("user", user)
                startActivity(intent)
            },
            onDelete = { user ->
                userViewModel.deleteUser(user.id)
            }
        )
    }
}

package com.example.dacs3_ticket_booking_app.data.repository

import com.example.dacs3_ticket_booking_app.data.model.User
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.auth.UserProfileChangeRequest
import com.google.firebase.firestore.FirebaseFirestore
import kotlinx.coroutines.tasks.await

class AuthRepository {

    private val firebaseAuth = FirebaseAuth.getInstance()
    private val db = FirebaseFirestore.getInstance()
    private val userCollection = db.collection("users")

    // ✅ Đăng ký (Register) - Chỉ tạo Auth, chưa tạo Firestore (chống hacker)
    suspend fun register(email: String, fullName: String, password: String): Result<String> {
        return try {
            val authResult = firebaseAuth.createUserWithEmailAndPassword(email, password).await()
            val user = authResult.user

            if (user != null) {
                // Cập nhật displayName
                val profileUpdate = UserProfileChangeRequest.Builder()
                    .setDisplayName(fullName)
                    .build()
                user.updateProfile(profileUpdate).await()

                // Gửi email xác thực
                user.sendEmailVerification().await()

                // ⚠️ KHÔNG lưu Firestore ngay - chỉ lưu khi user xác thực email bằng login
                Result.success(user.uid)
            } else {
                Result.failure(Exception("Lỗi tạo user"))
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Đăng nhập (Login) - Kiểm tra Firestore, không kiểm tra email verified
    suspend fun login(email: String, password: String): Result<Pair<String, String>> {
        return try {
            val authResult = firebaseAuth.signInWithEmailAndPassword(email, password).await()
            val user = authResult.user

            if (user != null) {
                // Lấy thông tin user từ Firestore
                val doc = userCollection.document(user.uid).get().await()
                val userData = doc.toObject(User::class.java)

                // Nếu user không tồn tại trong Firestore → email chưa được xác thực
                if (userData == null) {
                    user.sendEmailVerification().await()
                    return Result.failure(Exception("Vui lòng xác thực email trước khi đăng nhập"))
                }

                // Kiểm tra tài khoản bị khóa
                if (!userData.isActivate) {
                    return Result.failure(Exception("Tài khoản của bạn đã bị khóa"))
                }

                val role = userData.role ?: "user"
                Result.success(Pair(user.uid, role))
            } else {
                Result.failure(Exception("Lỗi đăng nhập"))
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy thông tin user từ Firestore
    suspend fun getUserFromFirestore(userId: String): Result<User?> {
        return try {
            val doc = userCollection.document(userId).get().await()
            val user = doc.toObject(User::class.java)
            Result.success(user)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy user hiện tại
    fun getCurrentUser(): String? {
        return firebaseAuth.currentUser?.uid
    }

    // ✅ Kiểm tra user đã đăng nhập
    fun isUserLoggedIn(): Boolean {
        return firebaseAuth.currentUser != null
    }

    // ...existing code...

    // ✅ Đăng xuất
    fun logout() {
        firebaseAuth.signOut()
    }

    // ✅ Admin tạo tài khoản - Lưu trực tiếp vào Firestore (bypass email verified)
    suspend fun createUserByAdmin(
        email: String,
        fullName: String,
        password: String,
        role: String = "user",
        avatar: String = ""
    ): Result<String> {
        return try {
            // Tạo tài khoản Firebase Auth
            val authResult = firebaseAuth.createUserWithEmailAndPassword(email, password).await()
            val user = authResult.user

            if (user != null) {
                // Cập nhật displayName
                val profileUpdate = UserProfileChangeRequest.Builder()
                    .setDisplayName(fullName)
                    .build()
                user.updateProfile(profileUpdate).await()

                // Lưu trực tiếp vào Firestore với isActivate=true (không cần xác thực email)
                val userData = User(
                    id = user.uid,
                    email = email,
                    fullName = fullName,
                    role = role,
                    isActivate = true,
                    avatar = avatar,
                    createdAt = System.currentTimeMillis(),
                    updatedAt = System.currentTimeMillis()
                )
                userCollection.document(user.uid).set(userData).await()

                // Gửi email xác thực (tùy chọn - để người dùng có thể đặt lại mật khẩu)
                user.sendEmailVerification().await()

                Result.success(user.uid)
            } else {
                Result.failure(Exception("Lỗi tạo user"))
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Cập nhật tiền tích lũy
    suspend fun updateAccumulatedMoney(userId: String, amount: Double): Result<Unit> {
        return try {
            val doc = userCollection.document(userId).get().await()
            val user = doc.toObject(User::class.java)

            if (user != null) {
                val newAmount = user.accumulatedMoney + amount
                userCollection.document(userId).update(
                    "accumulatedMoney", newAmount,
                    "updatedAt", System.currentTimeMillis()
                ).await()
                Result.success(Unit)
            } else {
                Result.failure(Exception("Không tìm thấy user"))
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

package com.example.dacs3_ticket_booking_app.data.repository

import com.example.dacs3_ticket_booking_app.data.model.User
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.auth.UserProfileChangeRequest
import com.google.firebase.firestore.FirebaseFirestore
import kotlinx.coroutines.tasks.await

class AuthRepository {

    private val firebaseAuth = FirebaseAuth.getInstance()
    private val db = FirebaseFirestore.getInstance()
    private val userCollection = db.collection("users")

    // ✅ Đăng ký (Register) - Chỉ tạo Auth, chưa tạo Firestore (chống hacker)
    suspend fun register(email: String, fullName: String, password: String): Result<String> {
        return try {
            val authResult = firebaseAuth.createUserWithEmailAndPassword(email, password).await()
            val user = authResult.user

            if (user != null) {
                // Cập nhật displayName
                val profileUpdate = UserProfileChangeRequest.Builder()
                    .setDisplayName(fullName)
                    .build()
                user.updateProfile(profileUpdate).await()

                // Gửi email xác thực
                user.sendEmailVerification().await()

                // ⚠️ KHÔNG lưu Firestore ngay - chỉ lưu khi user xác thực email bằng login
                Result.success(user.uid)
            } else {
                Result.failure(Exception("Lỗi tạo user"))
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Đăng nhập (Login) - Kiểm tra email verified, tự tạo Firestore lần đầu
    suspend fun login(email: String, password: String): Result<Pair<String, String>> {
        return try {
            val authResult = firebaseAuth.signInWithEmailAndPassword(email, password).await()
            val user = authResult.user

            if (user != null) {
                // ⭐ BƯỚC 1: Kiểm tra email đã xác thực chưa
                if (!user.isEmailVerified) {
                    user.sendEmailVerification().await()
                    return Result.failure(Exception("Vui lòng xác thực email trước khi đăng nhập"))
                }

                // ⭐ BƯỚC 2: Lấy thông tin user từ Firestore
                val doc = userCollection.document(user.uid).get().await()
                val userData = doc.toObject(User::class.java)

                // ⭐ BƯỚC 3: Nếu Firestore null nhưng email verified → Tạo user mới (lần đầu xác thực)
                if (userData == null) {
                    val newUser = User(
                        id = user.uid,
                        email = email,
                        fullName = user.displayName ?: "",
                        role = "user",
                        isActivate = true,
                        createdAt = System.currentTimeMillis(),
                        updatedAt = System.currentTimeMillis()
                    )
                    userCollection.document(user.uid).set(newUser).await()
                    return Result.success(Pair(user.uid, "user"))
                }

                // ⭐ BƯỚC 4: Kiểm tra tài khoản bị khóa (Admin tạo hoặc từ trước)
                if (!userData.isActivate) {
                    return Result.failure(Exception("Tài khoản của bạn đã bị khóa"))
                }

                val role = userData.role ?: "user"
                Result.success(Pair(user.uid, role))
            } else {
                Result.failure(Exception("Lỗi đăng nhập"))
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy thông tin user từ Firestore
    suspend fun getUserFromFirestore(userId: String): Result<User?> {
        return try {
            val doc = userCollection.document(userId).get().await()
            val user = doc.toObject(User::class.java)
            Result.success(user)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy user hiện tại
    fun getCurrentUser(): String? {
        return firebaseAuth.currentUser?.uid
    }

    // ✅ Kiểm tra user đã đăng nhập
    fun isUserLoggedIn(): Boolean {
        return firebaseAuth.currentUser != null
    }

    // ...existing code...

    // ✅ Đăng xuất
    fun logout() {
        firebaseAuth.signOut()
    }

    // ✅ Admin tạo tài khoản - Lưu trực tiếp vào Firestore (bypass email verified)
    suspend fun createUserByAdmin(
        email: String,
        fullName: String,
        password: String,
        role: String = "user",
        avatar: String = ""
    ): Result<String> {
        return try {
            // Tạo tài khoản Firebase Auth
            val authResult = firebaseAuth.createUserWithEmailAndPassword(email, password).await()
            val user = authResult.user

            if (user != null) {
                // Cập nhật displayName
                val profileUpdate = UserProfileChangeRequest.Builder()
                    .setDisplayName(fullName)
                    .build()
                user.updateProfile(profileUpdate).await()

                // Lưu trực tiếp vào Firestore với isActivate=true (không cần xác thực email)
                val userData = User(
                    id = user.uid,
                    email = email,
                    fullName = fullName,
                    role = role,
                    isActivate = true,
                    avatar = avatar,
                    createdAt = System.currentTimeMillis(),
                    updatedAt = System.currentTimeMillis()
                )
                userCollection.document(user.uid).set(userData).await()

                // Gửi email xác thực (tùy chọn - để người dùng có thể đặt lại mật khẩu)
                user.sendEmailVerification().await()

                Result.success(user.uid)
            } else {
                Result.failure(Exception("Lỗi tạo user"))
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Cập nhật tiền tích lũy
    suspend fun updateAccumulatedMoney(userId: String, amount: Double): Result<Unit> {
        return try {
            val doc = userCollection.document(userId).get().await()
            val user = doc.toObject(User::class.java)

            if (user != null) {
                val newAmount = user.accumulatedMoney + amount
                userCollection.document(userId).update(
                    "accumulatedMoney", newAmount,
                    "updatedAt", System.currentTimeMillis()
                ).await()
                Result.success(Unit)
            } else {
                Result.failure(Exception("Không tìm thấy user"))
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

package com.example.ticketbookingapp.ui.view.adaper

import android.content.Intent
import android.view.ViewGroup
import androidx.recyclerview.widget.RecyclerView
import androidx.viewpager2.widget.ViewPager2
import com.example.dacs3_ticket_booking_app.databinding.ViewholderSliderBinding
import android.content.Context
import android.view.LayoutInflater
import com.bumptech.glide.Glide
import com.bumptech.glide.load.resource.bitmap.CenterCrop
import com.bumptech.glide.load.resource.bitmap.RoundedCorners
import com.bumptech.glide.request.RequestOptions
import com.example.dacs3_ticket_booking_app.ui.view.DetailMovieActivity
import com.example.dacs3_ticket_booking_app.data.model.Banner


class BannerAdapter(
    private var sliderItems:MutableList<Banner>,
    private val viewPager2: ViewPager2

): RecyclerView.Adapter<BannerAdapter.SliderViewHolder>() {
    private var context: Context?=null
    private val runnable= Runnable{
        sliderItems.addAll(sliderItems)
        notifyDataSetChanged()
    }

    inner class SliderViewHolder(private val binding: ViewholderSliderBinding  ): RecyclerView.ViewHolder(binding.root) {
        fun bind(Banner: Banner) {
            context?.let{
                Glide.with(it)
                    .load(Banner.image)
                    .apply(
                        RequestOptions().transform(CenterCrop(), RoundedCorners(60))
                    )
                    .into(binding.imageSlider)
            }

            // Add click listener to navigate to detail movie
            binding.root.setOnClickListener {
                val intent = Intent(context, DetailMovieActivity::class.java)
                intent.putExtra("MOVIE_ID", Banner.movieId)
                context?.startActivity(intent)
            }
        }
    }
    override fun onCreateViewHolder(
        parent: ViewGroup,
        viewType: Int
    ): BannerAdapter.SliderViewHolder {
        context=parent.context
        val binding = ViewholderSliderBinding.inflate(LayoutInflater.from(context), parent, false)
        return SliderViewHolder(binding)
    }

    override fun onBindViewHolder(holder: BannerAdapter.SliderViewHolder, position: Int) {
        holder.bind(sliderItems[position])
        if (position == sliderItems.size - 2) {
            viewPager2.post(runnable)
        }
    }

    override fun getItemCount(): Int =sliderItems.size
}

