                _isLoading.value = false
            }
            result.onFailure { e ->
                _errorMessage.value = "Error loading bills: ${e.message}"
                _isLoading.value = false
            }
        }
    }

    fun getBillsByUser(userId: String) {
        _isLoading.value = true
        viewModelScope.launch {
            val result = billRepository.getBillsByUser(userId)
            result.onSuccess { list ->
                _bills.value = list
                _isLoading.value = false
            }
            result.onFailure { e ->
                _errorMessage.value = "Error loading bills: ${e.message}"
                _isLoading.value = false
            }
        }
    }

    fun getBillsByShowtime(showtimeId: String) {
        _isLoading.value = true
        viewModelScope.launch {
            val result = billRepository.getBillsByShowtime(showtimeId)
            result.onSuccess { list ->
                _bills.value = list
                _isLoading.value = false
            }
            result.onFailure { e ->
                _errorMessage.value = "Error loading bills: ${e.message}"
                _isLoading.value = false
            }
        }
    }

    fun addBill(bill: Bill) {
        _isLoading.value = true
        viewModelScope.launch {
            val result = billRepository.addBill(bill)
            result.onSuccess { id ->
                _successMessage.value = "Bill created successfully (ID: $id)"
                _isLoading.value = false
            }
            result.onFailure { e ->
                _errorMessage.value = "Error creating bill: ${e.message}"
                _isLoading.value = false
            }
        }
    }

    // ✅ Book multiple seats for a showtime
    fun bookSeats(showtimeId: String, seatPositions: List<String>) {
        _isLoading.value = true
        viewModelScope.launch {
            val result = showtimeRepository.addBookedSeats(showtimeId, seatPositions)
            result.onSuccess {
                _successMessage.value = "Seats booked successfully"
                _isLoading.value = false
            }
            result.onFailure { e ->
                _errorMessage.value = "Error booking seats: ${e.message}"
                _isLoading.value = false
            }
        }
    }

    fun cancelBill(billId: String) {
        _isLoading.value = true
        viewModelScope.launch {
            val result = billRepository.updateBillStatus(billId, "cancelled")
            result.onSuccess {
                _successMessage.value = "Bill cancelled successfully"
                _isLoading.value = false
                getAllBills()
            }
            result.onFailure { e ->
                _errorMessage.value = "Error cancelling bill: ${e.message}"
                _isLoading.value = false
            }
        }
    }

    fun getBillsByMovie(movieId: String) {
        _isLoading.value = true
        viewModelScope.launch {
            val result = billRepository.getBillsByMovie(movieId)
            result.onSuccess { list ->
                _bills.value = list
                _isLoading.value = false
            }
            result.onFailure { e ->
                _errorMessage.value = "Error loading bills: ${e.message}"
                _isLoading.value = false
            }
        }
    }
}

package com.example.dacs3_ticket_booking_app.utils

import android.content.Context
import android.net.Uri
import com.cloudinary.android.MediaManager
import com.cloudinary.android.callback.ErrorInfo
import com.cloudinary.android.callback.UploadCallback

object CloudinaryHelper {

    // Gọi hàm này 1 lần duy nhất trong Application.onCreate() hoặc tại AdminActivity
    fun init(context: Context) {
        val config = mapOf(
            "cloud_name" to "drmkkrmkw",
            "api_key"    to "282185291775257",
            "api_secret" to "wJSLylOsbT_xxTH081CFcDD_sBE"
        )
        MediaManager.init(context, config)
    }

    /**
     * Upload ảnh lên Cloudinary.
     * Ảnh sẽ lưu ở folder: TicketBooking
     * [onResult] trả về URL (String) nếu thành công, hoặc null nếu lỗi.
     */
    fun uploadImage(uri: Uri, context: Context, onResult: (String?) -> Unit) {
        MediaManager.get()
            .upload(uri)
            .option("folder", "TicketBooking")  // ✅ Folder trên Cloudinary
            .callback(object : UploadCallback {
                override fun onStart(requestId: String) {}
                override fun onProgress(requestId: String, bytes: Long, totalBytes: Long) {}

                override fun onSuccess(requestId: String, resultData: Map<*, *>) {
                    val url = resultData["secure_url"] as? String
                    onResult(url)
                }

                override fun onError(requestId: String, error: ErrorInfo) {
                    onResult(null)
                }

                override fun onReschedule(requestId: String, error: ErrorInfo) {
                    onResult(null)
                }
            })
            .dispatch(context)
    }
}

package com.example.dacs3_ticket_booking_app.utils

import android.content.Context
import android.net.Uri
import com.cloudinary.android.MediaManager
import com.cloudinary.android.callback.ErrorInfo
import com.cloudinary.android.callback.UploadCallback

object CloudinaryHelper {

    private var isInitialized = false

    // ✅ Init chỉ một lần duy nhất
    fun init(context: Context) {
        if (isInitialized) {
            android.util.Log.d("CloudinaryHelper", "Already initialized, skipping")
            return
        }

        try {
            val config = mapOf(
                "cloud_name" to "drmkkrmkw",
                "api_key"    to "282185291775257",
                "api_secret" to "wJSLylOsbT_xxTH081CFcDD_sBE"
            )
            MediaManager.init(context, config)
            isInitialized = true
            android.util.Log.d("CloudinaryHelper", "Cloudinary initialized successfully")
        } catch (e: Exception) {
            android.util.Log.e("CloudinaryHelper", "Init error: ${e.message}", e)
        }
    }

    /**
     * Upload ảnh lên Cloudinary.
     * Ảnh sẽ lưu ở folder: TicketBooking
     * [onResult] trả về URL (String) nếu thành công, hoặc null nếu lỗi.
     */
    fun uploadImage(uri: Uri, context: Context, onResult: (String?) -> Unit) {
        MediaManager.get()
            .upload(uri)
            .option("folder", "TicketBooking")  // ✅ Folder trên Cloudinary
            .callback(object : UploadCallback {
                override fun onStart(requestId: String) {}
                override fun onProgress(requestId: String, bytes: Long, totalBytes: Long) {}

                override fun onSuccess(requestId: String, resultData: Map<*, *>) {
                    val url = resultData["secure_url"] as? String
                    onResult(url)
                }

                override fun onError(requestId: String, error: ErrorInfo) {
                    onResult(null)
                }

                override fun onReschedule(requestId: String, error: ErrorInfo) {
                    onResult(null)
                }
            })
            .dispatch(context)
    }
}

