package com.example.dacs3_ticket_booking_app.ui.view.adaper

import android.content.Context
import android.view.LayoutInflater
import android.view.ViewGroup
import androidx.recyclerview.widget.RecyclerView
import com.bumptech.glide.Glide
import com.bumptech.glide.load.resource.bitmap.CenterCrop
import com.bumptech.glide.load.resource.bitmap.RoundedCorners
import com.bumptech.glide.request.RequestOptions
import com.example.dacs3_ticket_booking_app.data.model.Movie
import com.example.dacs3_ticket_booking_app.databinding.ViewholderFilmBinding

class MovieAdapter(private val items: MutableList<Movie>): RecyclerView.Adapter<MovieAdapter.ViewHolder>() {
    private var context: Context?=null
    inner class ViewHolder(private val binding: ViewholderFilmBinding): RecyclerView.ViewHolder(binding.root) {
        fun bind(movie: Movie) {
            binding.nameTxt.text=movie.title
            val requestOption= RequestOptions()
                .transform(CenterCrop(), RoundedCorners(30))
            Glide.with(context!!)
                .load(movie.poster)
                .apply(requestOption)
                .into(binding.picture)
        }
    }

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): MovieAdapter.ViewHolder {
        context=parent.context
        val binding= ViewholderFilmBinding.inflate(
            LayoutInflater.from(context), parent, false
        )
        return ViewHolder(binding)
    }

    override fun onBindViewHolder(holder: MovieAdapter.ViewHolder, position: Int) {
        holder.bind(items[position])
    }

    override fun getItemCount():Int=items.size
}

package com.example.dacs3_ticket_booking_app.ui.view.adaper

import android.content.Context
import android.content.Intent
import android.view.LayoutInflater
import android.view.ViewGroup
import androidx.recyclerview.widget.RecyclerView
import com.bumptech.glide.Glide
import com.bumptech.glide.load.resource.bitmap.CenterCrop
import com.bumptech.glide.load.resource.bitmap.RoundedCorners
import com.bumptech.glide.request.RequestOptions
import com.example.dacs3_ticket_booking_app.data.model.Movie
import com.example.dacs3_ticket_booking_app.databinding.ViewholderFilmBinding
import com.example.dacs3_ticket_booking_app.ui.view.DetailMovieActivity

class MovieAdapter(private val items: MutableList<Movie>): RecyclerView.Adapter<MovieAdapter.ViewHolder>() {
    private var context: Context?=null
    inner class ViewHolder(private val binding: ViewholderFilmBinding): RecyclerView.ViewHolder(binding.root) {
        fun bind(movie: Movie) {
            binding.nameTxt.text=movie.title
            val requestOption= RequestOptions()
                .transform(CenterCrop(), RoundedCorners(30))
            Glide.with(context!!)
                .load(movie.poster)
                .apply(requestOption)
                .into(binding.picture)

            // Add click listener to navigate to detail movie
            binding.root.setOnClickListener {
                val intent = Intent(context, DetailMovieActivity::class.java)
                intent.putExtra("MOVIE_ID", movie.id)
                context?.startActivity(intent)
            }
        }
    }

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): MovieAdapter.ViewHolder {
        context=parent.context
        val binding= ViewholderFilmBinding.inflate(
            LayoutInflater.from(context), parent, false
        )
        return ViewHolder(binding)
    }

    override fun onBindViewHolder(holder: MovieAdapter.ViewHolder, position: Int) {
        holder.bind(items[position])
    }

    override fun getItemCount():Int=items.size
}

package com.example.dacs3_ticket_booking_app.data.repository

import com.example.dacs3_ticket_booking_app.data.model.Movie
import com.google.firebase.firestore.FirebaseFirestore
import kotlinx.coroutines.tasks.await

class MovieRepository {

    private val db = FirebaseFirestore.getInstance()
    private val movieCollection = db.collection("movies")

    // ✅ Thêm phim (auto ID)
    suspend fun addMovie(movie: Movie): Result<String> {
        return try {
            val docRef = movieCollection.document()
            val movieWithId = movie.copy(id = docRef.id)

            docRef.set(movieWithId).await()
            Result.success(docRef.id)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy tất cả phim
    suspend fun getAllMovies(): Result<List<Movie>> {
        return try {
            val snapshot = movieCollection.get().await()
            val movies = snapshot.toObjects(Movie::class.java)
            Result.success(movies)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy theo ID
    suspend fun getMovieById(id: String): Result<Movie?> {
        return try {
            val doc = movieCollection.document(id).get().await()
            val movie = doc.toObject(Movie::class.java)
            Result.success(movie)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Update phim
    suspend fun updateMovie(movie: Movie): Result<Unit> {
        return try {
            movieCollection.document(movie.id)
                .set(movie)
                .await()

            Result.success(Unit)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Xóa phim
    suspend fun deleteMovie(movieId: String): Result<Unit> {
        return try {
            movieCollection.document(movieId)
                .delete()
                .await()

            Result.success(Unit)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    //  Lọc theo status
    suspend fun getMoviesByStatus(status: String): Result<List<Movie>> {
        return try {
            val snapshot = movieCollection
                .whereEqualTo("status", status)
                .get()
                .await()

            val movies = snapshot.toObjects(Movie::class.java)
            Result.success(movies)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    //  Lọc theo genre
    suspend fun getMoviesByGenre(genre: String): Result<List<Movie>> {
        return try {
            val snapshot = movieCollection
                .whereArrayContains("genres", genre)
                .get()
                .await()

            val movies = snapshot.toObjects(Movie::class.java)
            Result.success(movies)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

package com.example.dacs3_ticket_booking_app.data.repository

import com.example.dacs3_ticket_booking_app.data.model.Movie
import com.google.firebase.firestore.FirebaseFirestore
import kotlinx.coroutines.tasks.await

class MovieRepository {

    private val db = FirebaseFirestore.getInstance()
    private val movieCollection = db.collection("movies")

    // ✅ Thêm phim (auto ID)
    suspend fun addMovie(movie: Movie): Result<String> {
        return try {
            val docRef = movieCollection.document()
            val movieWithId = movie.copy(id = docRef.id)

            docRef.set(movieWithId).await()
            Result.success(docRef.id)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy tất cả phim
    suspend fun getAllMovies(): Result<List<Movie>> {
        return try {
            val snapshot = movieCollection.get().await()
            val movies = snapshot.toObjects(Movie::class.java)
            Result.success(movies)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy theo ID
    suspend fun getMovieById(id: String): Result<Movie?> {
        return try {
            val doc = movieCollection.document(id).get().await()
            val movie = doc.toObject(Movie::class.java)
            Result.success(movie)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Update phim
    suspend fun updateMovie(movie: Movie): Result<Unit> {
        return try {
            movieCollection.document(movie.id)
                .set(movie)
                .await()

            Result.success(Unit)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Xóa phim
    suspend fun deleteMovie(movieId: String): Result<Unit> {
        return try {
            movieCollection.document(movieId)
                .delete()
                .await()

            Result.success(Unit)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    //  Lọc theo status
    suspend fun getMoviesByStatus(status: String): Result<List<Movie>> {
        return try {
            val snapshot = movieCollection
                .whereEqualTo("status", status)
                .get()
                .await()

            val movies = snapshot.toObjects(Movie::class.java)
            Result.success(movies)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    //  Lọc theo genre
    suspend fun getMoviesByGenre(genre: String): Result<List<Movie>> {
        return try {
            val snapshot = movieCollection
                .whereArrayContains("genres", genre)
                .get()
                .await()

            val movies = snapshot.toObjects(Movie::class.java)
            Result.success(movies)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    //  Tim kiem phim theo tieu de (Client-side filtering)
    fun searchMoviesByTitle(movies: List<Movie>, query: String): List<Movie> {
        return movies.filter { it.title.contains(query, ignoreCase = true) }
    }

    // Sort phim theo ten (A-Z)
    fun sortMoviesByTitle(movies: List<Movie>, ascending: Boolean = true): List<Movie> {
        return if (ascending) {
            movies.sortedBy { it.title }
        } else {
            movies.sortedByDescending { it.title }
        }
    }

    // Sort phim theo nam phat hanh
    fun sortMoviesByYear(movies: List<Movie>, ascending: Boolean = false): List<Movie> {
        return if (ascending) {
            movies.sortedBy { it.year }
        } else {
            movies.sortedByDescending { it.year }
        }
    }

    // Sort phim theo thoi luong
    fun sortMoviesByDuration(movies: List<Movie>, ascending: Boolean = true): List<Movie> {
        return if (ascending) {
            movies.sortedBy { it.duration }
        } else {
            movies.sortedByDescending { it.duration }
        }
    }
}

package com.example.dacs3_ticket_booking_app.ui.view.dialog

import android.app.Dialog
import android.content.Context
import android.os.Bundle
import android.text.Editable
import android.text.TextWatcher
import android.widget.EditText
import android.widget.ImageView
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.recyclerview.widget.RecyclerView
import com.example.dacs3_ticket_booking_app.R
import com.example.dacs3_ticket_booking_app.data.model.Movie
import com.example.dacs3_ticket_booking_app.ui.view.adapter.MovieSearchAdapter

class MovieSearchDialog(
    context: Context,
    private val movies: List<Movie>,
    private val onMovieSelected: (Movie) -> Unit
) : Dialog(context) {

    private lateinit var etSearch: EditText
    private lateinit var ivClear: ImageView
    private lateinit var rvMovies: RecyclerView
    private lateinit var adapter: MovieSearchAdapter

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.dialog_movie_search)

        // Full screen style
        window?.setLayout(
            android.view.ViewGroup.LayoutParams.MATCH_PARENT,
            android.view.ViewGroup.LayoutParams.MATCH_PARENT
        )

        setupViews()
        setupRecyclerView()
        setupSearchListener()
    }

    private fun setupViews() {
        etSearch = findViewById(R.id.etSearchMovie)
        ivClear = findViewById(R.id.ivClear)
        rvMovies = findViewById(R.id.rvMovies)

        ivClear.setOnClickListener {
            etSearch.text.clear()
            adapter.filterByQuery("")
        }
    }

    private fun setupRecyclerView() {
        adapter = MovieSearchAdapter(
            movies = movies.toMutableList(),
            onMovieSelected = { movie ->
                onMovieSelected(movie)
                dismiss()
            }
        )
        rvMovies.adapter = adapter
        rvMovies.layoutManager = LinearLayoutManager(context)
    }

    private fun setupSearchListener() {
        etSearch.addTextChangedListener(object : TextWatcher {
            override fun afterTextChanged(s: Editable?) {}
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) {}
            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                val query = s?.toString()?.trim() ?: ""
                adapter.filterByQuery(query)
            }
        })
    }
}

