package com.example.dacs3_ticket_booking_app.ui.view.user

import android.content.Intent
import android.os.Bundle
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AppCompatActivity
import com.example.dacs3_ticket_booking_app.SplashActivity
import com.example.dacs3_ticket_booking_app.databinding.ActivityProfileBinding
import com.google.firebase.auth.FirebaseAuth

class ProfileActivity : AppCompatActivity() {
    private lateinit var binding: ActivityProfileBinding
    private lateinit var firebaseAuth: FirebaseAuth

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        binding = ActivityProfileBinding.inflate(layoutInflater)
        setContentView(binding.root)

        firebaseAuth = FirebaseAuth.getInstance()

        // ✅ Hiển thị thông tin user
        displayUserInfo()

        // ✅ Nút Cập nhật thông tin
        binding.updateInfoBtn.setOnClickListener {
            Toast.makeText(this, "Cập nhật thông tin", Toast.LENGTH_SHORT).show()
            // TODO: Mở dialog hoặc activity để cập nhật thông tin
        }

        // ✅ Nút Đổi mật khẩu
        binding.changePasswordBtn.setOnClickListener {
            Toast.makeText(this, "Đổi mật khẩu", Toast.LENGTH_SHORT).show()
            // TODO: Mở dialog hoặc activity để đổi mật khẩu
        }

        // ✅ Nút Logout
        binding.logoutBtn.setOnClickListener {
            logout()
        }
    }

    private fun displayUserInfo() {
        val currentUser = firebaseAuth.currentUser

        if (currentUser != null) {
            binding.userNameText.text = currentUser.displayName ?: "Chưa cập nhật tên"
            binding.userEmailText.text = currentUser.email ?: "Không có email"
        } else {
            binding.userNameText.text = "Chưa đăng nhập"
            binding.userEmailText.text = "---"
        }
    }

    private fun logout() {
        // ✅ Đăng xuất Firebase
        firebaseAuth.signOut()

        // ✅ Xóa session từ SharedPreferences
        val sharedPreferences = getSharedPreferences("app_prefs", MODE_PRIVATE)
        sharedPreferences.edit().apply {
            remove("userId")
            remove("role")
            putBoolean("isLoggedIn", false)
            apply()
        }

        Toast.makeText(this, "Đã đăng xuất", Toast.LENGTH_SHORT).show()

        // ✅ Quay lại Splash Screen
        startActivity(Intent(this, SplashActivity::class.java))
        finish()
    }
}

