    }

    private fun displayUserInfo() {
        val currentUser = firebaseAuth.currentUser

        if (currentUser != null) {
            binding.userNameText.text = currentUser.displayName ?: "Chưa cập nhật tên"
            binding.userEmailText.text = currentUser.email ?: "Không có email"
        } else {
            binding.userNameText.text = "Chưa đăng nhập"
            binding.userEmailText.text = "---"
        }
    }

    private fun logout() {
        // ✅ Đăng xuất Firebase
        firebaseAuth.signOut()

        // ✅ Xóa session từ SharedPreferences
        val sharedPreferences = getSharedPreferences("app_prefs", MODE_PRIVATE)
        sharedPreferences.edit().apply {
            remove("userId")
            remove("role")
            putBoolean("isLoggedIn", false)
            apply()
        }

        Toast.makeText(this, "Đã đăng xuất", Toast.LENGTH_SHORT).show()

        // ✅ Quay lại Splash Screen
        startActivity(Intent(this, SplashActivity::class.java))
        finish()
    }
}

package com.example.dacs3_ticket_booking_app.ui.view.auth

import android.content.Intent
import android.os.Bundle
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.ViewModelProvider
import com.example.dacs3_ticket_booking_app.databinding.ActivityRegisterBinding
import com.example.dacs3_ticket_booking_app.ui.viewmodel.AuthViewModel

class RegisterActivity : AppCompatActivity() {
    private lateinit var binding: ActivityRegisterBinding
    private lateinit var authViewModel: AuthViewModel

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        binding = ActivityRegisterBinding.inflate(layoutInflater)
        setContentView(binding.root)

        authViewModel = ViewModelProvider(this).get(AuthViewModel::class.java)

        // ✅ Nút Đăng ký
        binding.registerBtn.setOnClickListener {
            val email = binding.emailInput.text.toString().trim()
            val fullName = binding.fullNameInput.text.toString().trim()
            val password = binding.passwordInput.text.toString().trim()
            val confirmPassword = binding.confirmPasswordInput.text.toString().trim()

            if (validateInput(email, fullName, password, confirmPassword)) {
                authViewModel.register(email, fullName, password)
            }
        }

        // ✅ Link đến trang đăng nhập
        binding.loginLink.setOnClickListener {
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
        }

        // Observe ViewModel
        observeViewModel()
    }

    private fun validateInput(email: String, fullName: String, password: String, confirmPassword: String): Boolean {
        return when {
            email.isEmpty() -> {
                binding.emailInput.error = "Email không được để trống"
                false
            }
            fullName.isEmpty() -> {
                binding.fullNameInput.error = "Họ tên không được để trống"
                false
            }
            password.isEmpty() -> {
                binding.passwordInput.error = "Mật khẩu không được để trống"
                false
            }
            confirmPassword.isEmpty() -> {
                binding.confirmPasswordInput.error = "Vui lòng xác nhận mật khẩu"
                false
            }
            !android.util.Patterns.EMAIL_ADDRESS.matcher(email).matches() -> {
                binding.emailInput.error = "Email không hợp lệ"
                false
            }
            password.length < 6 -> {
                binding.passwordInput.error = "Mật khẩu phải có ít nhất 6 ký tự"
                false
            }
            password != confirmPassword -> {
                binding.confirmPasswordInput.error = "Mật khẩu không trùng khớp"
                false
            }
            fullName.length < 3 -> {
                binding.fullNameInput.error = "Họ tên phải có ít nhất 3 ký tự"
                false
            }
            else -> true
        }
    }

    private fun observeViewModel() {
        // ✅ Khi đăng ký thành công
        authViewModel.successMessage.observe(this) { message ->
            if (!message.isNullOrEmpty()) {
                Toast.makeText(this, message, Toast.LENGTH_SHORT).show()
                authViewModel.clearSuccessMessage()

                // Chuyển sang trang đăng nhập
                startActivity(Intent(this, LoginActivity::class.java))
                finish()
            }
        }

        // ✅ Khi có lỗi
        authViewModel.errorMessage.observe(this) { message ->
            if (!message.isNullOrEmpty()) {
                Toast.makeText(this, message, Toast.LENGTH_SHORT).show()
                authViewModel.clearErrorMessage()
            }
        }

        // ✅ Trạng thái loading
        authViewModel.isLoading.observe(this) { isLoading ->
            binding.registerBtn.isEnabled = !isLoading
        }
    }
}

package com.example.dacs3_ticket_booking_app.ui.view.auth

import android.content.Intent
import android.os.Bundle
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AppCompatActivity
import com.example.dacs3_ticket_booking_app.databinding.ActivityRegisterBinding
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.auth.UserProfileChangeRequest

class RegisterActivity : AppCompatActivity() {
    private lateinit var binding: ActivityRegisterBinding
    private lateinit var firebaseAuth: FirebaseAuth

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        binding = ActivityRegisterBinding.inflate(layoutInflater)
        setContentView(binding.root)

        firebaseAuth = FirebaseAuth.getInstance()

        // ✅ Nút Đăng ký
        binding.registerBtn.setOnClickListener {
            val email = binding.emailInput.text.toString().trim()
            val fullName = binding.fullNameInput.text.toString().trim()
            val password = binding.passwordInput.text.toString().trim()
            val confirmPassword = binding.confirmPasswordInput.text.toString().trim()

            if (validateInput(email, fullName, password, confirmPassword)) {
                register(email, fullName, password)
            }
        }

        // ✅ Link đến trang đăng nhập
        binding.loginLink.setOnClickListener {
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
        }
    }

    private fun validateInput(email: String, fullName: String, password: String, confirmPassword: String): Boolean {
        return when {
            email.isEmpty() -> {
                binding.emailInput.error = "Email không được để trống"
                false
            }
            fullName.isEmpty() -> {
                binding.fullNameInput.error = "Họ tên không được để trống"
                false
            }
            password.isEmpty() -> {
                binding.passwordInput.error = "Mật khẩu không được để trống"
                false
            }
            confirmPassword.isEmpty() -> {
                binding.confirmPasswordInput.error = "Vui lòng xác nhận mật khẩu"
                false
            }
            !android.util.Patterns.EMAIL_ADDRESS.matcher(email).matches() -> {
                binding.emailInput.error = "Email không hợp lệ"
                false
            }
            password.length < 6 -> {
                binding.passwordInput.error = "Mật khẩu phải có ít nhất 6 ký tự"
                false
            }
            password != confirmPassword -> {
                binding.confirmPasswordInput.error = "Mật khẩu không trùng khớp"
                false
            }
            fullName.length < 3 -> {
                binding.fullNameInput.error = "Họ tên phải có ít nhất 3 ký tự"
                false
            }
            else -> true
        }
    }

    private fun register(email: String, fullName: String, password: String) {
        binding.registerBtn.isEnabled = false

        firebaseAuth.createUserWithEmailAndPassword(email, password)
            .addOnCompleteListener { task ->
                if (task.isSuccessful) {
                    val user = firebaseAuth.currentUser
                    if (user != null) {
                        // Cập nhật profile với fullName
                        val profileUpdate = UserProfileChangeRequest.Builder()
                            .setDisplayName(fullName)
                            .build()

                        user.updateProfile(profileUpdate).addOnCompleteListener { updateTask ->
                            if (updateTask.isSuccessful) {
                                Toast.makeText(this, "Đăng ký thành công! Vui lòng đăng nhập.", Toast.LENGTH_SHORT).show()
                                startActivity(Intent(this, LoginActivity::class.java))
                                finish()
                            } else {
                                Toast.makeText(this, "Lỗi cập nhật profile: ${updateTask.exception?.message}", Toast.LENGTH_SHORT).show()
                                binding.registerBtn.isEnabled = true
                            }
                        }
                    }
                } else {
                    Toast.makeText(this, "Lỗi đăng ký: ${task.exception?.message}", Toast.LENGTH_SHORT).show()
                    binding.registerBtn.isEnabled = true
                }
            }
    }
}

