        billViewModel.addBill(bill)

        // ✅ Lắng nghe thành công tạo Bill
         billViewModel.successMessage.observe(this) { msg ->
             if (msg.contains("successfully")) {
                 // Extract bill ID từ message "Bill created successfully (ID: xyz)"
                 val regex = "\\(ID: ([^)]+)\\)".toRegex()
                 val matchResult = regex.find(msg)
                 val billId = matchResult?.groupValues?.get(1) ?: ""

                 if (billId.isNotEmpty()) {
                     android.util.Log.d("SeatListActivity", "✅ Bill created with ID: $billId")

                     // ✅ 2. Navigate to Payment Activity
                     val paymentIntent = Intent(this@SeatListActivity, PaymentActivity::class.java).apply {
                         putExtra(PaymentActivity.BILL_ID, billId)
                         putExtra(PaymentActivity.AMOUNT, (unitPrice * selectedSeats.size).toLong())
                         putExtra(PaymentActivity.SHOWTIME_ID, selectedShowtime.id)
                         putStringArrayListExtra(PaymentActivity.SELECTED_SEATS, ArrayList(selectedSeats))
                     }
                     startActivityForResult(paymentIntent, PAYMENT_REQUEST_CODE)
                 }
             }
         }
    }

    // ✅ Handle Payment Result
    override fun onActivityResult(requestCode: Int, resultCode: Int, data: android.content.Intent?) {
        super.onActivityResult(requestCode, resultCode, data)

        if (requestCode == PAYMENT_REQUEST_CODE) {
            when (resultCode) {
                RESULT_OK -> {
                    // ✅ Payment successful - continue to finish
                    android.util.Log.d("SeatListActivity", "✅ Payment successful!")
                    android.widget.Toast.makeText(
                        this,
                        "✅ Đã đặt vé thành công",
                        android.widget.Toast.LENGTH_LONG
                    ).show()

                    binding.root.postDelayed({
                        finish()
                    }, 2000)
                }
                RESULT_CANCELED -> {
                    // ❌ Payment failed - Bill deleted and seats unlocked by PaymentActivity
                    android.util.Log.d("SeatListActivity", "❌ Payment failed or cancelled!")
                    lockedPositions.clear()

                    android.widget.Toast.makeText(
                        this,
                        "❌ Thanh toán thất bại. Vui lòng thử lại",
                        android.widget.Toast.LENGTH_SHORT
                    ).show()
                }
            }
        }
    }

    companion object {
        private const val PAYMENT_REQUEST_CODE = 100
    }
}

 package com.example.dacs3_ticket_booking_app.utils

object SeatUtils {
    /**
     * Convert position "row_col" to readable name, e.g. "0_1" -> "A2"
     */
    fun positionToName(position: String): String {
        val parts = position.split("_")
        if (parts.size != 2) return position
        val row = parts[0].toIntOrNull() ?: return position
        val col = parts[1].toIntOrNull() ?: return position
        val rowChar = ('A' + row)
        val colNumber = col + 1
        return "$rowChar$colNumber"
    }

    /**
     * Convert a list of positions to display string, e.g. ["0_0","0_1"] -> "A1, A2"
     */
    fun positionsToDisplay(positions: List<String>): String {
        return positions.map { positionToName(it) }.joinToString(", ")
    }

     /**
     * Convert a single position to display string, e.g. "0_1" -> "A2"
     */
    fun positionToDisplay(position: String): String {
        return positionToName(position)
    }

    /**
     * Parse seat layout string into displayable grid
     * Input: "11111111" (8 ghế, KHÔNG có '0'/lối đi)
     * Output: list of SeatCell
     * Mặc định: 8 cột cố định
     * Hiển thị: A1, A2, A3, A4, A5, A6, A7, A8
     */
    fun parseSeatLayoutToDisplay(seatLayoutRow: String, rowIdx: Int): List<SeatCell> {
        val cells = mutableListOf<SeatCell>()

        seatLayoutRow.forEachIndexed { colIdx, char ->
            val pos = "${rowIdx}_${colIdx}"
            if (char == '1') {
                // Ghế ngồi - tính toán tên từ hàng + cột
                val seatName = "${('A' + rowIdx).toString()}${colIdx + 1}"  // A1, A2, ... A8
                cells.add(SeatCell(position = pos, name = seatName, isAisle = false))
            }
            // Bỏ hoàn toàn '0' - hệ thống KHÔNG có lối đi nữa
        }
        return cells
    }

    /**
     * Build complete seat grid from room layout
     * Không cần xử lý lối đi nữa
     */
    fun buildSeatGridFromRoom(seatLayout: List<String>): List<SeatCell> {
        val allCells = mutableListOf<SeatCell>()
        seatLayout.forEachIndexed { rowIdx, rowStr ->
            allCells.addAll(parseSeatLayoutToDisplay(rowStr, rowIdx))
        }
        return allCells
    }

    /**
     * Before 12:00 -> "morning"
     * 12:00 - 18:00 -> "afternoon"
     * After 18:00 -> "evening"
     */
    fun getPriceTier(startTimeMillis: Long): String {
        val cal = java.util.Calendar.getInstance().apply { timeInMillis = startTimeMillis }
        return when (cal.get(java.util.Calendar.HOUR_OF_DAY)) {
            in 0..11 -> "morning"
            in 12..17 -> "afternoon"
            else -> "evening"
        }
    }

    fun priceTierLabel(tier: String): String = when (tier) {
        "morning" -> "Sáng"
        "afternoon" -> "Chiều"
        "evening" -> "Tối"
        else -> tier
    }

    /**
     * Build a flat list of Seat UI items from a Room's seatLayout matrix
     * Each item: position "row_col", isAisle = true if char == '0'
     */
    data class SeatCell(
        val position: String,   // "row_col"
        val name: String,       // "A1"
        val isAisle: Boolean    // if true, render as empty space
    )

    fun buildSeatGrid(seatLayout: List<String>): List<SeatCell> {
        val cells = mutableListOf<SeatCell>()
        seatLayout.forEachIndexed { rowIdx, rowStr ->
            rowStr.forEachIndexed { colIdx, char ->
                val pos = "${rowIdx}_${colIdx}"
                val isAisle = char == '0'
                val name = if (isAisle) "" else positionToName(pos)
                cells.add(SeatCell(position = pos, name = name, isAisle = isAisle))
            }
        }
        return cells
    }
}

