    var timeSlot: String = "",       // NEW: "08:00-10:00", "10:30-12:30", etc
    var startTime: Long = 0L,        // epoch millis (calculated from screeningDate + timeSlot)
    var endTime: Long = 0L,          // epoch millis (calculated from screeningDate + timeSlot)
    // "morning" = before 12:00, "afternoon" = 12:00-18:00, "evening" = after 18:00
    var priceTier: String = "morning",
    // Booked seat positions stored as "row_col", e.g. ["0_1", "0_2"]
    var bookedSeats: List<String> = emptyList(),
    // Seats locked during checkout: position -> lock timestamp (epoch millis)
    var lockedSeats: Map<String, Long> = emptyMap()
) : Serializable

package com.example.dacs3_ticket_booking_app.data.repository

import com.example.dacs3_ticket_booking_app.data.model.Showtime
import com.google.firebase.firestore.FirebaseFirestore
import kotlinx.coroutines.tasks.await

class ShowtimeRepository {

    private val db = FirebaseFirestore.getInstance()
    private val showtimeCollection = db.collection("showtimes")

    // ✅ Thêm suất chiếu (kiểm tra trùng theo phòng, ngày, giờ)
    suspend fun addShowtime(showtime: Showtime): Result<String> {
        return try {
            // Kiểm tra xem suất chiếu đã tồn tại không
            val existing = showtimeCollection
                .whereEqualTo("roomId", showtime.roomId)
                .whereEqualTo("screeningDate", showtime.screeningDate)
                .whereEqualTo("timeSlot", showtime.timeSlot)
                .get()
                .await()

            if (!existing.isEmpty) {
                throw Exception("Suất chiếu ngày ${showtime.screeningDate} lúc ${showtime.timeSlot} đã tồn tại trong phòng này")
            }

            val docRef = showtimeCollection.document()
            val showtimeWithId = showtime.copy(id = docRef.id)
            docRef.set(showtimeWithId).await()
            Result.success(docRef.id)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy tất cả suất chiếu
    suspend fun getAllShowtimes(): Result<List<Showtime>> {
        return try {
            val snapshot = showtimeCollection.get().await()
            val list = snapshot.toObjects(Showtime::class.java)
            Result.success(list)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy suất chiếu theo movieId
    suspend fun getShowtimesByMovie(movieId: String): Result<List<Showtime>> {
        return try {
            val snapshot = showtimeCollection
                .whereEqualTo("movieId", movieId)
                .get()
                .await()
            val list = snapshot.toObjects(Showtime::class.java)
            Result.success(list)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy suất chiếu theo roomId
    suspend fun getShowtimesByRoom(roomId: String): Result<List<Showtime>> {
        return try {
            val snapshot = showtimeCollection
                .whereEqualTo("roomId", roomId)
                .get()
                .await()
            val list = snapshot.toObjects(Showtime::class.java)
            Result.success(list)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✨ NEW: Lấy suất chiếu theo roomId & ngày chiếu (dùng để tìm khung giờ trống)
    suspend fun getShowtimesByRoomAndDate(roomId: String, screeningDate: String): Result<List<Showtime>> {
        return try {
            val snapshot = showtimeCollection
                .whereEqualTo("roomId", roomId)
                .whereEqualTo("screeningDate", screeningDate)
                .get()
                .await()
            val list = snapshot.toObjects(Showtime::class.java)
            Result.success(list)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Cập nhật suất chiếu
    suspend fun updateShowtime(showtime: Showtime): Result<Unit> {
        return try {
            showtimeCollection.document(showtime.id).set(showtime).await()
            Result.success(Unit)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Xóa suất chiếu
    suspend fun deleteShowtime(showtimeId: String): Result<Unit> {
        return try {
            showtimeCollection.document(showtimeId).delete().await()
            Result.success(Unit)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    //  Lock ghế (Transaction an toàn, chống đặt trùng)
    // LOCK_TIMEOUT_MS = 5 phút (giảm từ 10 phút)
    suspend fun lockSeats(showtimeId: String, positions: List<String>): Result<Unit> {
        val LOCK_TIMEOUT_MS = 5 * 60 * 1000L  // ✅ Giảm xuống 5 phút
        val docRef = showtimeCollection.document(showtimeId)
        return try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(docRef)
                val showtime = snapshot.toObject(Showtime::class.java)
                    ?: throw Exception("Không tìm thấy suất chiếu")

                val now = System.currentTimeMillis()
                val booked = showtime.bookedSeats
                val locked = showtime.lockedSeats.toMutableMap()

                // Xóa các lock đã hết hạn
                locked.entries.removeIf { (_, ts) -> now - ts > LOCK_TIMEOUT_MS }

                // ✅ Kiểm tra xem ghế có available không (duyệt từng ghế)
                for (pos in positions) {
                    when {
                        booked.contains(pos) -> throw Exception("Ghế $pos đã được đặt rồi")
                        locked.containsKey(pos) -> throw Exception("Ghế $pos đang được giữ bởi người khác")
                    }
                }

                // ✅ Lock các ghế (thêm vào map)
                for (pos in positions) {
                    locked[pos] = now
                }

                // ✅ Cập nhật lockedSeats trên Firestore
                transaction.update(docRef, "lockedSeats", locked)
            }.await()
            Result.success(Unit)
        } catch (e: Exception) {
            android.util.Log.e("ShowtimeRepository", "❌ Lock seats failed: ${e.message}", e)
            Result.failure(e)
        }
    }

    // ✅ Xác nhận ghế sau thanh toán thành công (Transaction)
    suspend fun confirmBooking(showtimeId: String, positions: List<String>): Result<Unit> {
        val docRef = showtimeCollection.document(showtimeId)
        return try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(docRef)
                val showtime = snapshot.toObject(Showtime::class.java)
                    ?: throw Exception("Không tìm thấy suất chiếu")

                val booked = showtime.bookedSeats.toMutableList()
                val locked = showtime.lockedSeats.toMutableMap()

                // ✅ Thêm tất cả ghế vào danh sách booked
                for (pos in positions) {
                    if (!booked.contains(pos)) {
                        booked.add(pos)
                    }
                    locked.remove(pos)  // Bỏ lock
                }

                transaction.update(docRef, "bookedSeats", booked)
                transaction.update(docRef, "lockedSeats", locked)
            }.await()
            Result.success(Unit)
        } catch (e: Exception) {
            android.util.Log.e("ShowtimeRepository", "❌ Confirm booking failed: ${e.message}", e)
            Result.failure(e)
        }
    }

    // ✅ Mở khóa ghế khi user hủy / hết giờ thanh toán
    suspend fun releaseLockedSeats(showtimeId: String, positions: List<String>): Result<Unit> {
        val docRef = showtimeCollection.document(showtimeId)
        return try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(docRef)
                val showtime = snapshot.toObject(Showtime::class.java)
                    ?: throw Exception("Không tìm thấy suất chiếu")

                val locked = showtime.lockedSeats.toMutableMap()

                // ✅ Xóa lock cho từng ghế
                for (pos in positions) {
                    if (locked.containsKey(pos)) {
                        locked.remove(pos)
                        android.util.Log.d("ShowtimeRepository", "✅ Released lock for seat: $pos")
                    }
                }

                transaction.update(docRef, "lockedSeats", locked)
            }.await()
            Result.success(Unit)
        } catch (e: Exception) {
            android.util.Log.e("ShowtimeRepository", "❌ Release locked seats failed: ${e.message}", e)
            Result.failure(e)
        }
    }

    //  Tìm kiếm suất chiếu theo movie name + date range + time range (Client-side)
    suspend fun searchShowtimes(
        movieId: String? = null,
        startDate: String? = null,
        endDate: String? = null,
        allShowtimes: List<Showtime>
    ): Result<List<Showtime>> {
        return try {
            var filtered = allShowtimes

            // Lọc theo movieId
            if (movieId != null && movieId.isNotEmpty()) {
                filtered = filtered.filter { it.movieId == movieId }
            }

            // Lọc theo ngày chiếu (format: "dd/MM/yyyy")
            if (startDate != null && endDate != null) {
                filtered = filtered.filter { it.screeningDate >= startDate && it.screeningDate <= endDate }
            } else if (startDate != null) {
                filtered = filtered.filter { it.screeningDate >= startDate }
            } else if (endDate != null) {
                filtered = filtered.filter { it.screeningDate <= endDate }
            }

            Result.success(filtered)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    //  Sắp xếp suất chiếu theo ngày chiếu và khung giờ
    fun sortShowtimesByDate(showtimes: List<Showtime>, ascending: Boolean = true): List<Showtime> {
        return if (ascending) {
            showtimes.sortedWith(compareBy<Showtime> { it.screeningDate }.thenBy { it.timeSlot })
        } else {
            showtimes.sortedWith(compareBy<Showtime> { it.screeningDate }.thenBy { it.timeSlot }.reversed())
        }
    }

    //  Sắp xếp suất chiếu theo khung giá
    fun sortShowtimesByPriceTier(showtimes: List<Showtime>): List<Showtime> {
        val tierOrder = mapOf("morning" to 1, "afternoon" to 2, "evening" to 3)
        return showtimes.sortedBy { tierOrder[it.priceTier] ?: 0 }
    }

    // ✅ Add multiple seats to booked seats list (when creating bill with multiple seats)
    suspend fun addBookedSeats(showtimeId: String, seatPositions: List<String>): Result<Unit> {
        return try {
            val docRef = showtimeCollection.document(showtimeId)
            val showtime = docRef.get().await().toObject(Showtime::class.java)
                ?: throw Exception("Không tìm thấy suất chiếu")

            val bookedSeats = showtime.bookedSeats.toMutableList()

            // ✅ Thêm từng ghế nếu chưa có
            for (position in seatPositions) {
                if (!bookedSeats.contains(position)) {
                    bookedSeats.add(position)
                    android.util.Log.d("ShowtimeRepository", "✅ Added seat: $position")
                } else {
                    android.util.Log.w("ShowtimeRepository", "⚠️ Seat already booked: $position")
                }
            }

            docRef.update("bookedSeats", bookedSeats).await()
            android.util.Log.d("ShowtimeRepository", "✅ Successfully updated bookedSeats: ${bookedSeats.size} seats")
            Result.success(Unit)
        } catch (e: Exception) {
            android.util.Log.e("ShowtimeRepository", "❌ Add booked seats failed: ${e.message}", e)
            Result.failure(e)
        }
    }

    // ✅ Remove multiple seats from booked seats list (when cancelling bill with multiple seats)
    suspend fun removeBookedSeats(showtimeId: String, seatPositions: List<String>): Result<Unit> {
        return try {
            val docRef = showtimeCollection.document(showtimeId)
            val showtime = docRef.get().await().toObject(Showtime::class.java)
                ?: throw Exception("Không tìm thấy suất chiếu")

            val bookedSeats = showtime.bookedSeats.toMutableList()

            // ✅ Xóa từng ghế
            for (position in seatPositions) {
                if (bookedSeats.contains(position)) {
                    bookedSeats.remove(position)
                    android.util.Log.d("ShowtimeRepository", "✅ Removed seat: $position")
                } else {
                    android.util.Log.w("ShowtimeRepository", "⚠️ Seat not found: $position")
                }
            }

            docRef.update("bookedSeats", bookedSeats).await()
            android.util.Log.d("ShowtimeRepository", "✅ Successfully removed seats. Remaining: ${bookedSeats.size}")
            Result.success(Unit)
        } catch (e: Exception) {
            android.util.Log.e("ShowtimeRepository", "❌ Remove booked seats failed: ${e.message}", e)
            Result.failure(e)
        }
    }

    //  Lấy danh sách ngày chiếu duy nhất theo movieId
    suspend fun getScreeningDatesByMovie(movieId: String): Result<List<String>> {
        return try {
            val snapshot = showtimeCollection
                .whereEqualTo("movieId", movieId)
                .get()
                .await()
            val showtimes = snapshot.toObjects(Showtime::class.java)
            // Lấy ngày duy nhất và sắp xếp
            val uniqueDates = showtimes.map { it.screeningDate }.distinct().sorted()
            Result.success(uniqueDates)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ⏰ Lấy danh sách khung giờ theo movieId và ngày chiếu
    suspend fun getTimeSlotsByMovieAndDate(movieId: String, screeningDate: String): Result<List<String>> {
        return try {
            val snapshot = showtimeCollection
                .whereEqualTo("movieId", movieId)
                .whereEqualTo("screeningDate", screeningDate)
                .get()
                .await()
            val showtimes = snapshot.toObjects(Showtime::class.java)
            // Lấy khung giờ duy nhất (đã sắp xếp)
            val timeSlots = showtimes.map { it.timeSlot }.distinct()
            Result.success(timeSlots)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

package com.example.dacs3_ticket_booking_app.data.repository

import com.example.dacs3_ticket_booking_app.data.model.Showtime
import com.google.firebase.firestore.FirebaseFirestore
import kotlinx.coroutines.tasks.await

class ShowtimeRepository {

    private val db = FirebaseFirestore.getInstance()
    private val showtimeCollection = db.collection("showtimes")

    // ✅ Thêm suất chiếu (kiểm tra trùng theo phòng, ngày, giờ)
    suspend fun addShowtime(showtime: Showtime): Result<String> {
        return try {
            // Kiểm tra xem suất chiếu đã tồn tại không
            val existing = showtimeCollection
                .whereEqualTo("roomId", showtime.roomId)
                .whereEqualTo("screeningDate", showtime.screeningDate)
                .whereEqualTo("timeSlot", showtime.timeSlot)
                .get()
                .await()

            if (!existing.isEmpty) {
                throw Exception("Suất chiếu ngày ${showtime.screeningDate} lúc ${showtime.timeSlot} đã tồn tại trong phòng này")
            }

            val docRef = showtimeCollection.document()
            val showtimeWithId = showtime.copy(id = docRef.id)
            docRef.set(showtimeWithId).await()
            Result.success(docRef.id)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy tất cả suất chiếu
    suspend fun getAllShowtimes(): Result<List<Showtime>> {
        return try {
            val snapshot = showtimeCollection.get().await()
            val list = snapshot.toObjects(Showtime::class.java)
            Result.success(list)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy suất chiếu theo movieId
    suspend fun getShowtimesByMovie(movieId: String): Result<List<Showtime>> {
        return try {
            val snapshot = showtimeCollection
                .whereEqualTo("movieId", movieId)
                .get()
                .await()
            val list = snapshot.toObjects(Showtime::class.java)
            Result.success(list)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy suất chiếu theo roomId
    suspend fun getShowtimesByRoom(roomId: String): Result<List<Showtime>> {
        return try {
            val snapshot = showtimeCollection
                .whereEqualTo("roomId", roomId)
                .get()
                .await()
            val list = snapshot.toObjects(Showtime::class.java)
            Result.success(list)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✨ NEW: Lấy suất chiếu theo roomId & ngày chiếu (dùng để tìm khung giờ trống)
    suspend fun getShowtimesByRoomAndDate(roomId: String, screeningDate: String): Result<List<Showtime>> {
        return try {
            val snapshot = showtimeCollection
                .whereEqualTo("roomId", roomId)
                .whereEqualTo("screeningDate", screeningDate)
                .get()
                .await()
            val list = snapshot.toObjects(Showtime::class.java)
            Result.success(list)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Cập nhật suất chiếu
    suspend fun updateShowtime(showtime: Showtime): Result<Unit> {
        return try {
            showtimeCollection.document(showtime.id).set(showtime).await()
            Result.success(Unit)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Xóa suất chiếu
    suspend fun deleteShowtime(showtimeId: String): Result<Unit> {
        return try {
            showtimeCollection.document(showtimeId).delete().await()
            Result.success(Unit)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    //  Lock ghế (Transaction an toàn, chống đặt trùng)
    // LOCK_TIMEOUT_MS = 2 phút (auto unlock nếu quá 2p)
    suspend fun lockSeats(showtimeId: String, positions: List<String>): Result<Unit> {
        val LOCK_TIMEOUT_MS = 2 * 60 * 1000L  // ✅ 2 phút
        val docRef = showtimeCollection.document(showtimeId)
        return try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(docRef)
                val showtime = snapshot.toObject(Showtime::class.java)
                    ?: throw Exception("Không tìm thấy suất chiếu")

                val now = System.currentTimeMillis()
                val booked = showtime.bookedSeats
                val locked = showtime.lockedSeats.toMutableMap()

                // ✅ Xóa các lock đã hết hạn (>2 phút)
                locked.entries.removeIf { (_, ts) -> now - ts > LOCK_TIMEOUT_MS }

                // ✅ Kiểm tra xem ghế có available không
                for (pos in positions) {
                    when {
                        booked.contains(pos) -> throw Exception("Ghế $pos đã được đặt rồi")
                        locked.containsKey(pos) -> throw Exception("Ghế $pos đang được giữ bởi người khác")
                    }
                }

                // ✅ Lock các ghế (thêm vào map)
                for (pos in positions) {
                    locked[pos] = now
                }

                transaction.update(docRef, "lockedSeats", locked)
            }.await()
            Result.success(Unit)
        } catch (e: Exception) {
            android.util.Log.e("ShowtimeRepository", "❌ Lock seats failed: ${e.message}", e)
            Result.failure(e)
        }
    }

    // ✅ Xác nhận ghế sau thanh toán thành công (Transaction)
    suspend fun confirmBooking(showtimeId: String, positions: List<String>): Result<Unit> {
        val docRef = showtimeCollection.document(showtimeId)
        return try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(docRef)
                val showtime = snapshot.toObject(Showtime::class.java)
                    ?: throw Exception("Không tìm thấy suất chiếu")

                val booked = showtime.bookedSeats.toMutableList()
                val locked = showtime.lockedSeats.toMutableMap()

                // ✅ Thêm tất cả ghế vào danh sách booked
                for (pos in positions) {
                    if (!booked.contains(pos)) {
                        booked.add(pos)
                    }
                    locked.remove(pos)  // Bỏ lock
                }

                transaction.update(docRef, "bookedSeats", booked)
                transaction.update(docRef, "lockedSeats", locked)
            }.await()
            Result.success(Unit)
        } catch (e: Exception) {
            android.util.Log.e("ShowtimeRepository", "❌ Confirm booking failed: ${e.message}", e)
            Result.failure(e)
        }
    }

    // ✅ Mở khóa ghế khi user hủy / hết giờ thanh toán
    suspend fun releaseLockedSeats(showtimeId: String, positions: List<String>): Result<Unit> {
        val docRef = showtimeCollection.document(showtimeId)
        return try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(docRef)
                val showtime = snapshot.toObject(Showtime::class.java)
                    ?: throw Exception("Không tìm thấy suất chiếu")

                val locked = showtime.lockedSeats.toMutableMap()

                // ✅ Xóa lock cho từng ghế
                for (pos in positions) {
                    if (locked.containsKey(pos)) {
                        locked.remove(pos)
                        android.util.Log.d("ShowtimeRepository", "✅ Released lock for seat: $pos")
                    }
                }

                transaction.update(docRef, "lockedSeats", locked)
            }.await()
            Result.success(Unit)
        } catch (e: Exception) {
            android.util.Log.e("ShowtimeRepository", "❌ Release locked seats failed: ${e.message}", e)
            Result.failure(e)
        }
    }

    //  Tìm kiếm suất chiếu theo movie name + date range + time range (Client-side)
    suspend fun searchShowtimes(
        movieId: String? = null,
        startDate: String? = null,
        endDate: String? = null,
        allShowtimes: List<Showtime>
    ): Result<List<Showtime>> {
        return try {
            var filtered = allShowtimes

            // Lọc theo movieId
            if (movieId != null && movieId.isNotEmpty()) {
                filtered = filtered.filter { it.movieId == movieId }
            }

            // Lọc theo ngày chiếu (format: "dd/MM/yyyy")
            if (startDate != null && endDate != null) {
                filtered = filtered.filter { it.screeningDate >= startDate && it.screeningDate <= endDate }
            } else if (startDate != null) {
                filtered = filtered.filter { it.screeningDate >= startDate }
            } else if (endDate != null) {
                filtered = filtered.filter { it.screeningDate <= endDate }
            }

            Result.success(filtered)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    //  Sắp xếp suất chiếu theo ngày chiếu và khung giờ
    fun sortShowtimesByDate(showtimes: List<Showtime>, ascending: Boolean = true): List<Showtime> {
        return if (ascending) {
            showtimes.sortedWith(compareBy<Showtime> { it.screeningDate }.thenBy { it.timeSlot })
        } else {
            showtimes.sortedWith(compareBy<Showtime> { it.screeningDate }.thenBy { it.timeSlot }.reversed())
        }
    }

    //  Sắp xếp suất chiếu theo khung giá
    fun sortShowtimesByPriceTier(showtimes: List<Showtime>): List<Showtime> {
        val tierOrder = mapOf("morning" to 1, "afternoon" to 2, "evening" to 3)
        return showtimes.sortedBy { tierOrder[it.priceTier] ?: 0 }
    }

    // ✅ Add multiple seats to booked seats list (when creating bill with multiple seats)
    suspend fun addBookedSeats(showtimeId: String, seatPositions: List<String>): Result<Unit> {
        return try {
            val docRef = showtimeCollection.document(showtimeId)
            val showtime = docRef.get().await().toObject(Showtime::class.java)
                ?: throw Exception("Không tìm thấy suất chiếu")

            val bookedSeats = showtime.bookedSeats.toMutableList()

            // ✅ Thêm từng ghế nếu chưa có
            for (position in seatPositions) {
                if (!bookedSeats.contains(position)) {
                    bookedSeats.add(position)
                    android.util.Log.d("ShowtimeRepository", "✅ Added seat: $position")
                } else {
                    android.util.Log.w("ShowtimeRepository", "⚠️ Seat already booked: $position")
                }
            }

            docRef.update("bookedSeats", bookedSeats).await()
            android.util.Log.d("ShowtimeRepository", "✅ Successfully updated bookedSeats: ${bookedSeats.size} seats")
            Result.success(Unit)
        } catch (e: Exception) {
            android.util.Log.e("ShowtimeRepository", "❌ Add booked seats failed: ${e.message}", e)
            Result.failure(e)
        }
    }

    // ✅ Remove multiple seats from booked seats list (when cancelling bill with multiple seats)
    suspend fun removeBookedSeats(showtimeId: String, seatPositions: List<String>): Result<Unit> {
        return try {
            val docRef = showtimeCollection.document(showtimeId)
            val showtime = docRef.get().await().toObject(Showtime::class.java)
                ?: throw Exception("Không tìm thấy suất chiếu")

            val bookedSeats = showtime.bookedSeats.toMutableList()

            // ✅ Xóa từng ghế
            for (position in seatPositions) {
                if (bookedSeats.contains(position)) {
                    bookedSeats.remove(position)
                    android.util.Log.d("ShowtimeRepository", "✅ Removed seat: $position")
                } else {
                    android.util.Log.w("ShowtimeRepository", "⚠️ Seat not found: $position")
                }
            }

            docRef.update("bookedSeats", bookedSeats).await()
            android.util.Log.d("ShowtimeRepository", "✅ Successfully removed seats. Remaining: ${bookedSeats.size}")
            Result.success(Unit)
        } catch (e: Exception) {
            android.util.Log.e("ShowtimeRepository", "❌ Remove booked seats failed: ${e.message}", e)
            Result.failure(e)
        }
    }

    //  Lấy danh sách ngày chiếu duy nhất theo movieId
    suspend fun getScreeningDatesByMovie(movieId: String): Result<List<String>> {
        return try {
            val snapshot = showtimeCollection
                .whereEqualTo("movieId", movieId)
                .get()
                .await()
            val showtimes = snapshot.toObjects(Showtime::class.java)
            // Lấy ngày duy nhất và sắp xếp
            val uniqueDates = showtimes.map { it.screeningDate }.distinct().sorted()
            Result.success(uniqueDates)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ⏰ Lấy danh sách khung giờ theo movieId và ngày chiếu
    suspend fun getTimeSlotsByMovieAndDate(movieId: String, screeningDate: String): Result<List<String>> {
        return try {
            val snapshot = showtimeCollection
                .whereEqualTo("movieId", movieId)
                .whereEqualTo("screeningDate", screeningDate)
                .get()
                .await()
            val showtimes = snapshot.toObjects(Showtime::class.java)
            // Lấy khung giờ duy nhất (đã sắp xếp)
            val timeSlots = showtimes.map { it.timeSlot }.distinct()
            Result.success(timeSlots)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

package com.example.dacs3_ticket_booking_app.ui.viewmodel

import android.util.Log
import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.dacs3_ticket_booking_app.data.model.Showtime
import com.example.dacs3_ticket_booking_app.data.repository.ShowtimeRepository
import kotlinx.coroutines.launch

class ShowtimeViewModel : ViewModel() {
    private val showtimeRepository = ShowtimeRepository()

    private val _showtimes = MutableLiveData<List<Showtime>>()
    val showtimes: LiveData<List<Showtime>> = _showtimes

    //  Danh sách ngày chiếu
    private val _screeningDates = MutableLiveData<List<String>>()
    val screeningDates: LiveData<List<String>> = _screeningDates

    // ⏰ Danh sách khung giờ
    private val _timeSlots = MutableLiveData<List<String>>()
    val timeSlots: LiveData<List<String>> = _timeSlots

    //  Suất chiếu được chọn
    private val _selectedShowtime = MutableLiveData<Showtime?>()
    val selectedShowtime: LiveData<Showtime?> = _selectedShowtime

    private val _isLoading = MutableLiveData<Boolean>()
    val isLoading: LiveData<Boolean> = _isLoading

    private val _errorMessage = MutableLiveData<String>()
    val errorMessage: LiveData<String> = _errorMessage

    private val _successMessage = MutableLiveData<String>()
    val successMessage: LiveData<String> = _successMessage

    fun getAllShowtimes() {
        _isLoading.value = true
        viewModelScope.launch {
            val result = showtimeRepository.getAllShowtimes()
            result.onSuccess { list ->
                _showtimes.value = list
                _isLoading.value = false
            }
            result.onFailure { e ->
                _errorMessage.value = "Lỗi tải suất chiếu: ${e.message}"
                _isLoading.value = false
            }
        }
    }

    fun getShowtimesByMovie(movieId: String) {
        _isLoading.value = true
        viewModelScope.launch {
            val result = showtimeRepository.getShowtimesByMovie(movieId)
            result.onSuccess { list ->
                _showtimes.value = list
                _isLoading.value = false
            }
            result.onFailure { e ->
                _errorMessage.value = "Lỗi tải suất chiếu: ${e.message}"
                _isLoading.value = false
            }
        }
    }

    fun getShowtimesByRoom(roomId: String) {
        _isLoading.value = true
        viewModelScope.launch {
            val result = showtimeRepository.getShowtimesByRoom(roomId)
            result.onSuccess { list ->
                _showtimes.value = list
                _isLoading.value = false
            }
            result.onFailure { e ->
                _errorMessage.value = "Lỗi tải suất chiếu: ${e.message}"
                _isLoading.value = false
            }
        }
    }

    // ✨ NEW: Lấy showtimes theo phòng & ngày (dùng để tìm khung giờ trống)
    fun getShowtimesByRoomAndDate(roomId: String, date: String, callback: (List<Showtime>) -> Unit) {
        viewModelScope.launch {
            val result = showtimeRepository.getShowtimesByRoomAndDate(roomId, date)
            result.onSuccess { list ->
                callback(list)
            }
            result.onFailure { e ->
                _errorMessage.value = "Lỗi tải suất chiếu: ${e.message}"
                callback(emptyList())
            }
        }
    }

    fun addShowtime(showtime: Showtime) {
        _isLoading.value = true
        viewModelScope.launch {
            val result = showtimeRepository.addShowtime(showtime)
            result.onSuccess { id ->
                _successMessage.value = "Thêm suất chiếu thành công (ID: $id)"
                _isLoading.value = false
                getAllShowtimes()
            }
            result.onFailure { e ->
                _errorMessage.value = "Lỗi thêm suất chiếu: ${e.message}"
                _isLoading.value = false
            }
        }
    }

     fun updateShowtime(showtime: Showtime) {
        _isLoading.value = true
        viewModelScope.launch {
            val result = showtimeRepository.updateShowtime(showtime)
            result.onSuccess {
                _successMessage.value = "Cập nhật suất chiếu thành công"
                _isLoading.value = false
                getAllShowtimes()
            }
            result.onFailure { e ->
                _errorMessage.value = "Lỗi cập nhật suất chiếu: ${e.message}"
                _isLoading.value = false
            }
        }
    }

    fun deleteShowtime(showtimeId: String) {
        _isLoading.value = true
        viewModelScope.launch {
            val result = showtimeRepository.deleteShowtime(showtimeId)
            result.onSuccess {
                _successMessage.value = "Xóa suất chiếu thành công"
                _isLoading.value = false
                getAllShowtimes()
            }
            result.onFailure { e ->
                _errorMessage.value = "Lỗi xóa suất chiếu: ${e.message}"
                _isLoading.value = false
            }
        }
    }

    //  Lock ghế (chống đặt trùng)
    fun lockSeats(showtimeId: String, positions: List<String>) {
        _isLoading.value = true
        viewModelScope.launch {
            val result = showtimeRepository.lockSeats(showtimeId, positions)
            result.onSuccess {
                _successMessage.value = "Giữ ghế thành công"
                _isLoading.value = false
            }
            result.onFailure { e ->
                _errorMessage.value = "Không thể giữ ghế: ${e.message}"
                _isLoading.value = false
            }
        }
    }

    // ✅ Xác nhận booking sau thanh toán
    fun confirmBooking(showtimeId: String, positions: List<String>) {
        viewModelScope.launch {
            val result = showtimeRepository.confirmBooking(showtimeId, positions)
            result.onSuccess {
                _successMessage.value = "Đặt ghế thành công"
            }
            result.onFailure { e ->
                _errorMessage.value = "Lỗi xác nhận ghế: ${e.message}"
            }
        }
    }

    // ❌ Hủy lock khi user cancel / timeout
    fun releaseLockedSeats(showtimeId: String, positions: List<String>) {
        viewModelScope.launch {
            val result = showtimeRepository.releaseLockedSeats(showtimeId, positions)
            result.onSuccess {
                Log.d("ShowtimeViewModel", "✅ Released locked seats: $positions")
            }
            result.onFailure { e ->
                Log.e("ShowtimeViewModel", "❌ Failed to release locked seats: ${e.message}", e)
                _errorMessage.value = "Lỗi nhả lock ghế: ${e.message}"
            }
        }
    }

    //  Load danh sách ngày chiếu theo movieId
    fun loadScreeningDates(movieId: String) {
        _isLoading.value = true
        viewModelScope.launch {
            // Trước tiên load tất cả suất chiếu của phim
            val showtimesResult = showtimeRepository.getShowtimesByMovie(movieId)
            showtimesResult.onSuccess { showtimes ->
                _showtimes.value = showtimes

                // Rồi extract danh sách ngày duy nhất
                val uniqueDates = showtimes.map { it.screeningDate }.distinct().sorted()
                _screeningDates.value = uniqueDates
                _isLoading.value = false
            }
            showtimesResult.onFailure { e ->
                _errorMessage.value = "Lỗi tải ngày chiếu: ${e.message}"
                _isLoading.value = false
            }
        }
    }

    // ⏰ Load danh sách khung giờ theo movieId và ngày
    fun loadTimeSlots(movieId: String, screeningDate: String) {
        _isLoading.value = true
        viewModelScope.launch {
            val result = showtimeRepository.getTimeSlotsByMovieAndDate(movieId, screeningDate)
            result.onSuccess { slots ->
                _timeSlots.value = slots
                _isLoading.value = false
            }
            result.onFailure { e ->
                _errorMessage.value = "Lỗi tải khung giờ: ${e.message}"
                _isLoading.value = false
            }
        }
    }

    //  Lưu suất chiếu được chọn
    fun selectShowtime(showtime: Showtime) {
        _selectedShowtime.value = showtime
    }
}

