package com.example.dacs3_ticket_booking_app.ui.viewmodel

import android.content.Context
import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.ViewModel
import com.google.firebase.auth.FirebaseAuth

class SplashViewModel : ViewModel() {

    private val firebaseAuth = FirebaseAuth.getInstance()

    private val _navigationEvent = MutableLiveData<String>()
    val navigationEvent: LiveData<String> = _navigationEvent

    // ✅ Kiểm tra user và role từ SharedPreferences
    fun checkUserAndNavigate(context: Context) {
        val firebaseUser = firebaseAuth.currentUser

        if (firebaseUser != null) {
            // User đã đăng nhập Firebase, lấy role từ SharedPreferences
            val sharedPreferences = context.getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
            val role = sharedPreferences.getString("role", "user") ?: "user"

            _navigationEvent.value = if (role == "admin") "admin" else "user"
        } else {
            // Chưa đăng nhập
            _navigationEvent.value = "login"
        }
    }
}

package com.example.dacs3_ticket_booking_app.ui.viewmodel

import android.content.Context
import android.util.Log
import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.ViewModel

class SplashViewModel : ViewModel() {

    private val _navigationEvent = MutableLiveData<String>()
    val navigationEvent: LiveData<String> = _navigationEvent

    // ✅ Chỉ dựa vào SharedPreferences (source of truth)
    fun checkUserAndNavigate(context: Context) {
        val sharedPreferences = context.getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
        val isLoggedIn = sharedPreferences.getBoolean("isLoggedIn", false)
        val userId = sharedPreferences.getString("userId", "")
        val role = sharedPreferences.getString("role", "")

        // DEBUG LOG
        Log.d("SplashViewModel", "=== CHECK USER ===")
        Log.d("SplashViewModel", "isLoggedIn: $isLoggedIn")
        Log.d("SplashViewModel", "userId: '$userId'")
        Log.d("SplashViewModel", "role: '$role' (trim: '${role?.trim()}')")

        // ✅ Kiểm tra SharedPreferences (không dùng FirebaseAuth!)
        val destination = if (isLoggedIn && !userId.isNullOrEmpty() && !role.isNullOrEmpty()) {
            val trimmedRole = role.trim().lowercase()
            Log.d("SplashViewModel", "trimmedRole: '$trimmedRole'")

            if (trimmedRole == "admin") {
                Log.d("SplashViewModel", "Navigate to: admin")
                "admin"
            } else {
                Log.d("SplashViewModel", "Navigate to: user")
                "user"
            }
        } else {
            Log.d("SplashViewModel", "Navigate to: login (not logged in)")
            "login"
        }

        _navigationEvent.value = destination
    }
}

package com.example.dacs3_ticket_booking_app.data.repository

import com.example.dacs3_ticket_booking_app.data.model.Ticket
import com.google.firebase.firestore.FirebaseFirestore
import kotlinx.coroutines.tasks.await

class TicketRepository {

    private val db = FirebaseFirestore.getInstance()
    private val ticketCollection = db.collection("tickets")

    // ✅ Thêm vé mới
    suspend fun addTicket(ticket: Ticket): Result<String> {
        return try {
            val docRef = ticketCollection.document()
            val ticketWithId = ticket.copy(id = docRef.id)
            docRef.set(ticketWithId).await()
            Result.success(docRef.id)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy tất cả vé (Admin)
    suspend fun getAllTickets(): Result<List<Ticket>> {
        return try {
            val snapshot = ticketCollection.get().await()
            val list = snapshot.toObjects(Ticket::class.java)
            Result.success(list)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy vé theo userId
    suspend fun getTicketsByUser(userId: String): Result<List<Ticket>> {
        return try {
            val snapshot = ticketCollection
                .whereEqualTo("userId", userId)
                .get()
                .await()
            val list = snapshot.toObjects(Ticket::class.java)
            Result.success(list)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy vé theo showtimeId
    suspend fun getTicketsByShowtime(showtimeId: String): Result<List<Ticket>> {
        return try {
            val snapshot = ticketCollection
                .whereEqualTo("showtimeId", showtimeId)
                .get()
                .await()
            val list = snapshot.toObjects(Ticket::class.java)
            Result.success(list)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Cập nhật trạng thái vé (VD: paid -> cancelled)
    suspend fun updateTicketStatus(ticketId: String, status: String): Result<Unit> {
        return try {
            ticketCollection.document(ticketId).update("status", status).await()
            Result.success(Unit)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Xóa vé
    suspend fun deleteTicket(ticketId: String): Result<Unit> {
        return try {
            ticketCollection.document(ticketId).delete().await()
            Result.success(Unit)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

