package com.example.dacs3_ticket_booking_app.ui.view.adapter

import android.view.LayoutInflater
import android.view.ViewGroup
import androidx.recyclerview.widget.RecyclerView
import com.example.dacs3_ticket_booking_app.data.model.Bill
import com.example.dacs3_ticket_booking_app.databinding.ItemUserBillBinding
import com.example.dacs3_ticket_booking_app.utils.SeatUtils
import java.text.SimpleDateFormat
import java.util.*

class UserBillAdapter(
    private val items: MutableList<Bill>
) : RecyclerView.Adapter<UserBillAdapter.ViewHolder>() {

    private val sdf = SimpleDateFormat("dd/MM/yyyy HH:mm", Locale.getDefault())

    inner class ViewHolder(private val binding: ItemUserBillBinding) :
        RecyclerView.ViewHolder(binding.root) {
        fun bind(bill: Bill) {
            binding.tvBillId.text = "Bill #${bill.id.take(8)}"
            binding.tvBookingTime.text = "Booked: ${sdf.format(Date(bill.bookingTime))}"

            // Display list of seats
            val seatsDisplay = bill.seatPositions.joinToString(", ") { SeatUtils.positionToDisplay(it) }
            val seatCount = bill.seatPositions.size
            binding.tvSeats.text = "Seats: $seatsDisplay ($seatCount ghế)"

            // ✅ Tính tổng tiền = price (giá đơn vị) * số lượng ghế
            val totalPrice = bill.price * seatCount
            binding.tvTotalPrice.text = "Total: ${totalPrice.toInt()}đ"

            binding.tvStatus.text = when (bill.status) {
                "paid" -> "Paid"
                "cancelled" -> "Cancelled"
                else -> bill.status
            }

            // Color based on status
            binding.tvStatus.setTextColor(
                when (bill.status) {
                    "paid" -> binding.root.context.resources.getColor(android.R.color.holo_green_light, null)
                    "cancelled" -> binding.root.context.resources.getColor(android.R.color.holo_red_light, null)
                    else -> binding.root.context.resources.getColor(android.R.color.white, null)
                }
            )
        }
    }

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): ViewHolder {
        val binding = ItemUserBillBinding.inflate(LayoutInflater.from(parent.context), parent, false)
        return ViewHolder(binding)
    }

    override fun onBindViewHolder(holder: ViewHolder, position: Int) = holder.bind(items[position])
    override fun getItemCount(): Int = items.size
}

package com.example.dacs3_ticket_booking_app.ui.view.adapter

import android.view.LayoutInflater
import android.view.ViewGroup
import androidx.recyclerview.widget.RecyclerView
import com.example.dacs3_ticket_booking_app.data.model.Bill
import com.example.dacs3_ticket_booking_app.databinding.ItemUserBillBinding
import com.example.dacs3_ticket_booking_app.utils.SeatUtils
import java.text.SimpleDateFormat
import java.util.*

class UserBillAdapter(
    private val items: MutableList<Bill>,
    private val onItemClick: ((Bill) -> Unit)? = null
) : RecyclerView.Adapter<UserBillAdapter.ViewHolder>() {

    private val sdf = SimpleDateFormat("dd/MM/yyyy HH:mm", Locale.getDefault())

    inner class ViewHolder(private val binding: ItemUserBillBinding) :
        RecyclerView.ViewHolder(binding.root) {
        fun bind(bill: Bill) {
            binding.tvBillId.text = "Bill #${bill.id.take(8)}"
            binding.tvBookingTime.text = "Booked: ${sdf.format(Date(bill.bookingTime))}"
            
            // Display list of seats
            val seatsDisplay = bill.seatPositions.joinToString(", ") { SeatUtils.positionToDisplay(it) }
            val seatCount = bill.seatPositions.size
            binding.tvSeats.text = "Seats: $seatsDisplay ($seatCount ghế)"
            
            // ✅ Tính tổng tiền = price (giá đơn vị) * số lượng ghế
            val totalPrice = bill.price * seatCount
            binding.tvTotalPrice.text = "Total: ${totalPrice.toInt()}đ"
            
            binding.tvStatus.text = when (bill.status) {
                "paid" -> "Paid"
                "cancelled" -> "Cancelled"
                else -> bill.status
            }
            
            // Color based on status
            binding.tvStatus.setTextColor(
                when (bill.status) {
                    "paid" -> binding.root.context.resources.getColor(android.R.color.holo_green_light, null)
                    "cancelled" -> binding.root.context.resources.getColor(android.R.color.holo_red_light, null)
                    else -> binding.root.context.resources.getColor(android.R.color.white, null)
                }
            )

            // ✅ Add click listener
            binding.root.setOnClickListener {
                onItemClick?.invoke(bill)
            }
        }
    }

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): ViewHolder {
        val binding = ItemUserBillBinding.inflate(LayoutInflater.from(parent.context), parent, false)
        return ViewHolder(binding)
    }

    override fun onBindViewHolder(holder: ViewHolder, position: Int) = holder.bind(items[position])
    override fun getItemCount(): Int = items.size
}

package com.example.dacs3_ticket_booking_app.data.repository

import com.example.dacs3_ticket_booking_app.data.model.User
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.firestore.FirebaseFirestore
import kotlinx.coroutines.tasks.await

class UserRepository {
    private val firebaseAuth = FirebaseAuth.getInstance()
    private val authRepository = AuthRepository()

    private val db = FirebaseFirestore.getInstance()
    private val userCollection = db.collection("users")

    // ✅ Lấy tất cả users
    suspend fun getAllUsers(): Result<List<User>> {
        return try {
            val snapshot = userCollection.get().await()
            val users = snapshot.toObjects(User::class.java)
            Result.success(users)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy user theo ID
    suspend fun getUserById(userId: String): Result<User?> {
        return try {
            val doc = userCollection.document(userId).get().await()
            val user = doc.toObject(User::class.java)
            Result.success(user)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
    suspend fun createUser(user: User): Result<String> {
        return try {
            userCollection.document(user.id).set(user).await()
            Result.success(user.id)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
    suspend fun createUserAuth(email:String, password:String): Result<String> {
        return try {
            val authResult = firebaseAuth.createUserWithEmailAndPassword(email, password).await()
            val user = authResult.user
            if(user!=null){
                Result.success(user.uid)
            }
            else{
                Result.failure(Exception("User creation failed"))
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
    // ✅ Xóa user
    suspend fun deleteUser(userId: String): Result<Unit> {
        return try {
            userCollection.document(userId).delete().await()
            Result.success(Unit)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
    // ✅ Cập nhật role user
    suspend fun updateUserRole(userId: String, newRole: String): Result<Unit> {
        return try {
            userCollection.document(userId).update(
                "role", newRole,
                "updatedAt", System.currentTimeMillis()
            ).await()
            Result.success(Unit)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Cập nhật thông tin user
    suspend fun updateUser(user: User): Result<Unit> {
        return try {
            userCollection.document(user.id).set(user).await()
            Result.success(Unit)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    // ✅ Lấy users theo role
    suspend fun getUsersByRole(role: String): Result<List<User>> {
        return try {
            val snapshot = userCollection.whereEqualTo("role", role).get().await()
            val users = snapshot.toObjects(User::class.java)
            Result.success(users)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

